class o{constructor(){this.activeTab="geral",this.init()}init(){this.setupTabs(),this.setupPDFButton(),this.setupPrintButton(),this.restoreActiveTab()}setupTabs(){document.querySelectorAll('[data-bs-toggle="tab"]').forEach(e=>{e.addEventListener("shown.bs.tab",a=>{var r;this.activeTab=((r=a.target.getAttribute("data-bs-target"))==null?void 0:r.replace("#",""))||"geral",this.saveActiveTab()})})}saveActiveTab(){const t=new URL(window.location);t.searchParams.set("aba_ativa",this.activeTab),window.history.replaceState({},"",t)}restoreActiveTab(){const e=new URLSearchParams(window.location.search).get("aba_ativa");if(e){const a=document.querySelector(`[data-bs-target="#${e}"]`);a&&(new bootstrap.Tab(a).show(),this.activeTab=e)}}setupPDFButton(){const t=document.getElementById("btnGerarPDF");t&&t.addEventListener("click",async()=>{if(typeof html2pdf>"u"){alert("Biblioteca de PDF não carregada");return}t.disabled=!0,t.innerHTML='<span class="spinner-border spinner-border-sm"></span> Gerando...';try{await this.generatePDF()}catch(e){console.error("Erro ao gerar PDF:",e),alert("Erro ao gerar PDF")}finally{t.disabled=!1,t.innerHTML='<i class="bi bi-file-pdf"></i> Gerar PDF'}})}async generatePDF(){const t=document.querySelector(".tab-pane.active");if(!t){alert("Nenhuma aba ativa encontrada");return}const i={margin:10,filename:`SGC_${({geral:"Relatório Geral",metricas:"Métricas e Estatísticas",etapas:"Relatório por Etapas"}[this.activeTab]||"Relatório").replace(/\s/g,"_")}_${this.getDateString()}.pdf`,image:{type:"jpeg",quality:.98},html2canvas:{scale:2,useCORS:!0},jsPDF:{unit:"mm",format:"a4",orientation:"landscape"}},n=t.cloneNode(!0);n.style.width="100%",n.style.padding="20px",n.querySelectorAll(".no-print, button").forEach(s=>s.remove()),await html2pdf().set(i).from(n).save()}setupPrintButton(){const t=document.getElementById("btnImprimir");t&&t.addEventListener("click",()=>{const e=new URLSearchParams(window.location.search);e.set("aba_ativa",this.activeTab),window.open(`/solicitacoes/relatorios/imprimir?${e.toString()}`,"_blank")})}getDateString(){const t=new Date;return`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,"0")}-${String(t.getDate()).padStart(2,"0")}`}}document.addEventListener("DOMContentLoaded",()=>{window.relatoriosPage=new o});
